const bugs = [
  { id: 'BUG-2041', title: 'Dashboard fails to load when user has more than 200 projects', reporter: 'user@acme.com', description: 'When a workspace has more than 200 projects, the main dashboard page returns a 504 Gateway Timeout. This affects approximately 12 enterprise accounts. The error started appearing after the v2.4.1 deployment on July 12.', environment: 'production', browser: 'Chrome 126, Firefox 127', affected_users: 12, steps_to_reproduce: 'Create a workspace with 200+ projects, log in, navigate to dashboard' },
  { id: 'BUG-2042', title: 'Task assignee dropdown loses selection on mobile Safari', reporter: 'support@acme.com', description: 'On iOS 17.4 with Safari, selecting an assignee from the dropdown in a task card resets to empty when the user scrolls the page. Does not occur on Chrome mobile.', environment: 'production', browser: 'Safari iOS 17.4', affected_users: null, steps_to_reproduce: 'Open a task on mobile Safari, tap assignee dropdown, select a user, scroll page' },
  { id: 'BUG-2043', title: 'CSV export missing custom field columns', reporter: 'pm@acme.com', description: 'When exporting tasks to CSV, columns for custom fields (text, number, date) are missing from the exported file. Standard fields (title, due date, assignee) are present. This was working before the v2.4.0 release.', environment: 'production', browser: 'N/A', affected_users: null, steps_to_reproduce: 'Create a project with custom fields, add tasks with custom field values, export to CSV' }
];
return [{ json: { bugs, product: 'ProjectFlow', engineering_team_context: 'Three engineers on web, two on mobile, one on data/exports' } }];

const { bugs, product, engineering_team_context } = $input.first().json;
const bugsText = bugs.map(b => `  [${b.id}] ${b.title}
  Reporter: ${b.reporter} | Env: ${b.environment} | Affected users: ${b.affected_users ?? 'unknown'}
  Description: ${b.description}
  Steps: ${b.steps_to_reproduce}`).join('

');
const system = `You are a senior engineer performing bug triage for a SaaS product. You classify severity accurately (P0 = production down/data loss risk, P1 = major feature broken for many users, P2 = feature broken for some users/workaround exists, P3 = minor/cosmetic). You identify the engineering area, estimate reproduction difficulty, and suggest precise reproduction steps. Return ONLY valid JSON.`;
const user = `Triage these ${bugs.length} bug reports for: ${product}
Engineering context: ${engineering_team_context}

Bugs:
${bugsText}

Return JSON:
{
  "triaged_bugs": [
    {
      "id": "string",
      "severity": "P0|P1|P2|P3",
      "severity_rationale": "string",
      "engineering_area": "string — e.g. backend/api, frontend/web, mobile/ios, data/exports",
      "likely_cause": "string — hypothesis about root cause",
      "reproduction_steps": ["string"],
      "reproduction_difficulty": "easy|medium|hard",
      "suggested_owner": "string — which team/role should own this",
      "workaround": "string|null",
      "regression": true
    }
  ],
  "triage_summary": "string — 2-3 sentences covering the most critical issue and overall health signal"
}`;
return [{ json: { bugs, product, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Triage Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.triaged_bugs || !Array.isArray(parsed.triaged_bugs)) return [{ json: { _error: true, reason: 'Missing triaged_bugs' } }];
const p0 = parsed.triaged_bugs.filter(b => b.severity === 'P0').length;
return [{ json: { _error: false, triage: parsed, meta: { product: upstream.product, bug_count: upstream.bugs.length, p0_count: p0, generated_at: new Date().toISOString() } } }];

const { triage: t, meta: m } = $input.first().json;
const severityOrder = ['P0','P1','P2','P3'];
const sorted = [...(t.triaged_bugs||[])].sort((a,b) => severityOrder.indexOf(a.severity) - severityOrder.indexOf(b.severity));
const bugLines = sorted.map(b => [
  `  [${b.severity}] ${b.id} | ${b.engineering_area} | Owner: ${b.suggested_owner}${b.regression?' [REGRESSION]':''}`,
  `  Rationale: ${b.severity_rationale}`,
  `  Likely cause: ${b.likely_cause}`,
  `  Workaround: ${b.workaround || 'none'}`,
  `  Repro (${b.reproduction_difficulty}): ${b.reproduction_steps.join(' → ')}`,
  ''
].join('\n')).join('\n');
const report = [
  `BUG TRIAGE: ${m.product}`,
  `Generated: ${m.generated_at} | Bugs: ${m.bug_count}${m.p0_count > 0 ? ' | ⚠️ P0 COUNT: '+m.p0_count : ''}`,
  ``,
  `SUMMARY: ${t.triage_summary}`,
  ``,
  `TRIAGED BUGS (severity order):`,
  bugLines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
